var grupoAtual=null,currentUser=null,isAdm=false,isSuperAdmin=false,peladaAtual=null,allPeladas=[],admName='',admPassword='',admNames=[],superAdminName='',cachedJogadores=[],cachedPresentes=[],realtimeChannel=null;
